// Process decay candidates and generate alerts
const candidates = $input.all().map(i => i.json);

if (candidates.length === 0) {
  return [{ json: { has_decay: false, alerts: [], summary: 'No content decay detected' } }];
}

const alerts = candidates.map(c => ({
  type: 'content_decay',
  severity: c.decline_percent >= 50 ? 'critical' : c.decline_percent >= 30 ? 'warning' : 'info',
  page: c.page,
  current_sessions: c.current_sessions,
  historical_sessions: c.historical_sessions,
  decline_percent: Math.round(c.decline_percent),
  message: `${c.page}: -${Math.round(c.decline_percent)}% (${c.current_sessions} vs ${c.historical_sessions} sessions)`
}));

const critical = alerts.filter(a => a.severity === 'critical').length;
const warning = alerts.filter(a => a.severity === 'warning').length;

return [{ 
  json: { 
    has_decay: true, 
    alerts,
    critical_count: critical,
    warning_count: warning,
    total_count: alerts.length,
    summary: `${critical} critical, ${warning} warning, ${alerts.length} total decaying pages`
  } 
}];
